import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../services/api';
import Cronometro from '../components/Cronometro';
import UploadFotos from '../components/UploadFotos';

function NovaOS() {
    const navigate = useNavigate();
    const [clientes, setClientes] = useState([]);
    const [categorias, setCategorias] = useState([]);
    const [osId, setOsId] = useState(null);
    const [loading, setLoading] = useState(false);
    const [form, setForm] = useState({
        cliente_id: '',
        categoria_id: '',
        equipamento: '',
        modelo: '',
        imei: '',
        defeito: '',
        tipo_atendimento: 'presencial',
        estimativa_horas: '',
        preco_final: ''
    });
    const [servicoRealizado, setServicoRealizado] = useState('');
    const [statusOs, setStatusOs] = useState('aberto');

    useEffect(() => {
        const load = async () => {
            try {
                const [clientesRes, catRes] = await Promise.all([
                    api.get('/clientes'),
                    api.get('/categorias')
                ]);
                setClientes(clientesRes.data);
                setCategorias(catRes.data);
            } catch (err) {
                console.error(err);
                alert('Erro ao carregar dados. Verifique o backend.');
            }
        };
        load();
    }, []);

    const gerarNumeroOS = () => {
        const ano = new Date().getFullYear();
        return `${ano}${String(Math.floor(Math.random() * 10000)).padStart(4, '0')}`;
    };

    useEffect(() => {
        if (form.categoria_id) {
            const cat = categorias.find(c => c.id === parseInt(form.categoria_id));
            if (cat) {
                setForm(prev => ({
                    ...prev,
                    preco_final: cat.preco_sugerido || '',
                    estimativa_horas: cat.tempo_estimado_minutos ? (cat.tempo_estimado_minutos / 60).toFixed(2) : ''
                }));
            }
        }
    }, [form.categoria_id, categorias]);

    const handleChange = (e) => {
        setForm({ ...form, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!form.cliente_id) return alert('Selecione um cliente');
        setLoading(true);
        try {
            const novaOS = {
                ...form,
                numero_os: gerarNumeroOS(),
                estimativa_horas: form.estimativa_horas ? parseFloat(form.estimativa_horas) : null,
                preco_final: form.preco_final ? parseFloat(form.preco_final) : null
            };
            const res = await api.post('/os', novaOS);
            setOsId(res.data.id);
            alert('OS criada! Agora você pode iniciar o cronômetro e anexar fotos.');
        } catch (err) {
            console.error(err);
            alert('Erro ao criar OS: ' + (err.response?.data?.error || err.message));
        } finally {
            setLoading(false);
        }
    };

    const handleSalvarServico = async () => {
        if (!osId) return;
        try {
            await api.put(`/os/${osId}`, { servico_realizado: servicoRealizado, status_os: statusOs });
            alert('Serviço e status atualizados');
        } catch (err) {
            alert('Erro ao atualizar');
        }
    };

    if (osId) {
        return (
            <div style={{ maxWidth: '800px', margin: '0 auto' }}>
                <h2>OS #{osId} em andamento</h2>
                <Cronometro osId={osId} />
                <UploadFotos osId={osId} />
                <div style={{ marginTop: '20px' }}>
                    <label><strong>Serviço realizado (editável):</strong></label>
                    <textarea
                        rows="4"
                        value={servicoRealizado}
                        onChange={e => setServicoRealizado(e.target.value)}
                        style={{ width: '100%', padding: '8px', marginTop: '5px' }}
                        placeholder="Descreva o que foi feito..."
                    />
                </div>
                <div style={{ marginTop: '10px' }}>
                    <label><strong>Status:</strong></label>
                    <select value={statusOs} onChange={e => setStatusOs(e.target.value)} style={{ marginLeft: '10px', padding: '5px' }}>
                        <option value="aberto">Aberto</option>
                        <option value="analise">Em análise</option>
                        <option value="aguardando_peca">Aguardando peça</option>
                        <option value="concluido">Concluído</option>
                        <option value="entregue">Entregue</option>
                    </select>
                </div>
                <div style={{ marginTop: '20px' }}>
                    <button onClick={handleSalvarServico} style={{ marginRight: '10px', padding: '8px 16px' }}>Salvar serviço e status</button>
                    <button onClick={() => navigate('/')} style={{ padding: '8px 16px' }}>Voltar à Home</button>
                </div>
            </div>
        );
    }

    return (
        <div style={{ maxWidth: '600px', margin: '0 auto' }}>
            <h2>Nova Ordem de Serviço</h2>
            <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                <div>
                    <label>Cliente *</label>
                    <select name="cliente_id" value={form.cliente_id} onChange={handleChange} required style={{ width: '100%', padding: '6px' }}>
                        <option value="">Selecione</option>
                        {clientes.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
                    </select>
                </div>
                <div>
                    <label>Categoria</label>
                    <select name="categoria_id" value={form.categoria_id} onChange={handleChange} style={{ width: '100%', padding: '6px' }}>
                        <option value="">Selecione</option>
                        {categorias.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
                    </select>
                </div>
                <div>
                    <label>Equipamento</label>
                    <input type="text" name="equipamento" value={form.equipamento} onChange={handleChange} style={{ width: '100%', padding: '6px' }} />
                </div>
                <div>
                    <label>Modelo</label>
                    <input type="text" name="modelo" value={form.modelo} onChange={handleChange} style={{ width: '100%', padding: '6px' }} />
                </div>
                <div>
                    <label>IMEI (para celular)</label>
                    <input type="text" name="imei" value={form.imei} onChange={handleChange} style={{ width: '100%', padding: '6px' }} />
                </div>
                <div>
                    <label>Defeito relatado</label>
                    <textarea name="defeito" value={form.defeito} onChange={handleChange} rows="3" style={{ width: '100%', padding: '6px' }} />
                </div>
                <div>
                    <label>Tipo de atendimento</label>
                    <select name="tipo_atendimento" value={form.tipo_atendimento} onChange={handleChange} style={{ width: '100%', padding: '6px' }}>
                        <option value="presencial">Presencial</option>
                        <option value="remoto">Remoto</option>
                    </select>
                </div>
                <div>
                    <label>Estimativa (horas)</label>
                    <input type="number" step="0.5" name="estimativa_horas" value={form.estimativa_horas} onChange={handleChange} style={{ width: '100%', padding: '6px' }} />
                </div>
                <div>
                    <label>Preço final (R$)</label>
                    <input type="number" step="0.01" name="preco_final" value={form.preco_final} onChange={handleChange} style={{ width: '100%', padding: '6px' }} />
                </div>
                <button type="submit" disabled={loading} style={{ padding: '10px', backgroundColor: '#007bff', color: 'white', border: 'none', cursor: 'pointer' }}>
                    {loading ? 'Criando...' : 'Criar OS'}
                </button>
            </form>
        </div>
    );
}

export default NovaOS;
